fn test_cluster_store_too_few_entries() {
        let store = ClusterStore::new();
        let entries: Vec<(String, Vec<f32>)> = vec![
            ("a".into(), vec![0.0, 0.0]),
            ("b".into(), vec![1.0, 1.0]),
        ];
        // Less than 3 entries should not recompute
        assert!(!store.maybe_recompute(&entries));
        assert!(store.is_degraded());
    }
